class CachedData<T> {
  final T data;
  final DateTime cachedAt;
  final Duration? expiresIn;

  CachedData({
    required this.data,
    required this.cachedAt,
    this.expiresIn,
  });

  bool get isExpired {
    if (expiresIn == null) return false;
    return DateTime.now().difference(cachedAt) > expiresIn!;
  }

  Map<String, dynamic> toJson(Map<String, dynamic> Function(T) dataToJson) {
    return {
      'data': dataToJson(data),
      'cachedAt': cachedAt.toIso8601String(),
      'expiresIn': expiresIn?.inSeconds,
    };
  }

  factory CachedData.fromJson(
    Map<String, dynamic> json,
    T Function(Map<String, dynamic>) dataFromJson,
  ) {
    return CachedData(
      data: dataFromJson(json['data'] as Map<String, dynamic>),
      cachedAt: DateTime.parse(json['cachedAt'] as String),
      expiresIn: json['expiresIn'] != null ? Duration(seconds: json['expiresIn'] as int) : null,
    );
  }
}

class OfflineDataManager {
  final LocalStorageManager _storage;

  OfflineDataManager(this._storage);

  Future<void> saveCachedData<T>(
