  CachedData<T>? getCachedData<T>(
    String key,
    T Function(Map<String, dynamic>) fromJson,
  ) {
    final content = _storage.getCachedContent(key);
    if (content == null) return null;
    try {
      final cachedData = CachedData.fromJson(content, fromJson);
      if (cachedData.isExpired) {
        _storage.removeCachedContent(key);
        return null;
      }
      return cachedData;
    } catch (e) {
      debugPrint('Error parsing cached data: $e');
      return null;
    }
  }

  Future<void> clearExpiredCache() async {
    final keys = _storage.getAllKeys();
    for (final key in keys) {
      if (key.startsWith('cached_content_')) {
        final content = _storage.getCachedContent(key.replaceFirst('cached_content_', ''));
